SELECT COUNT(*) AS membership_count
FROM user_group_memberships
WHERE user_id = '1';

SELECT user_id
FROM password_reset_requests
WHERE request_date = (
    SELECT MAX(request_date)
    FROM password_reset_requests
);

SELECT username
FROM users
WHERE user_id = '0';

SELECT u.username
FROM users u
WHERE u.user_id IN (SELECT user_id FROM password_reset_requests);
